customCSS:
/* Emphasize blocks and luck */
.stat-card.blocks {
  grid-column: span 2;
  background: linear-gradient(135deg, rgba(168, 85, 247, 0.2) 0%, rgba(59, 157, 255, 0.1) 100%);
  border: 2px solid rgba(168, 85, 247, 0.4);
}

.stat-card.blocks .stat-value {
  font-size: 3rem;
  color: var(--neon-purple);
  text-shadow: 0 0 30px rgba(168, 85, 247, 0.5);
}

.stat-card.difficulty {
  background: linear-gradient(135deg, rgba(244, 114, 182, 0.2) 0%, rgba(168, 85, 247, 0.1) 100%);
  border: 2px solid rgba(244, 114, 182, 0.4);
}

.stat-card.difficulty .stat-value {
  color: var(--neon-pink);
  text-shadow: 0 0 20px rgba(244, 114, 182, 0.5);
}

/* Highlight block finders in miner list */
.miner-card[data-blocks-found]:not([data-blocks-found='0']) {
  border: 2px solid var(--neon-purple);
  box-shadow: 0 0 20px rgba(168, 85, 247, 0.3);
}

.miner-card[data-blocks-found]:not([data-blocks-found='0'])::after {
  content: 'BLOCK FINDER';
  position: absolute;
  top: -10px;
  right: 10px;
  background: var(--neon-purple);
  color: white;
  font-size: 0.7rem;
  padding: 2px 8px;
  border-radius: 4px;
  font-family: var(--font-display);
}

/* Lifetime section emphasis */
.lifetime-card:nth-child(2) {
  background: linear-gradient(135deg, rgba(168, 85, 247, 0.15) 0%, rgba(26, 31, 46, 1) 100%);
  border: 2px solid rgba(168, 85, 247, 0.3);
}

.lifetime-card:nth-child(2) .lifetime-value {
  font-size: 2rem;
}

.lifetime-card:nth-child(3) {
  background: linear-gradient(135deg, rgba(244, 114, 182, 0.15) 0%, rgba(26, 31, 46, 1) 100%);
  border: 2px solid rgba(244, 114, 182, 0.3);
}
